mapper.select:
SELECT c.id, c.name, c.image_url, c.total_price, c.is_free, c.status, c.recommended, c.course_type, c.teacher, c.chapter_count, c.question_count, c.exam_count, c.video_count, c.student_count, c.view_count, c.create_time, m.name AS major_name FROM edu_course c LEFT JOIN edu_major m ON c.major_id = m.id AND m.deleted = 0 WHERE c.deleted = 0
AND c.name LIKE CONCAT('%', #{query.name}, '%')
AND c.major_id = #{query.majorId}
AND c.status = #{query.status}
ORDER BY c.sort ASC, c.id DESC
